<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Falling Sand — Cellular Automata Sandbox</title>
<style>
  :root{
    --bg:#0a0e14;
    --panel:#141a24;
    --panel2:#1b2330;
    --border:#2a3445;
    --text:#e6edf3;
    --muted:#8b949e;
    --accent:#58a6ff;
    --danger:#ff6b6b;
  }
  *{box-sizing:border-box}
  html,body{margin:0;padding:0}
  body{
    background:
      radial-gradient(1200px 600px at 50% -10%, #1a2540 0%, transparent 60%),
      radial-gradient(800px 500px at 90% 110%, #1a2030 0%, transparent 55%),
      var(--bg);
    color:var(--text);
    font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,sans-serif;
    min-height:100vh;
    display:flex;
    flex-direction:column;
    align-items:center;
    padding:24px 16px 40px;
  }
  h1{
    font-weight:200;
    letter-spacing:6px;
    font-size:26px;
    margin:0 0 2px;
    text-transform:uppercase;
    background:linear-gradient(90deg,#e0c068,#58a6ff,#7fd44a);
    -webkit-background-clip:text;
    background-clip:text;
    color:transparent;
  }
  .sub{color:var(--muted);font-size:11px;letter-spacing:2px;text-transform:uppercase;margin-bottom:18px}
  .wrap{display:flex;gap:18px;align-items:flex-start;flex-wrap:wrap;justify-content:center}
  .canvas-wrap{
    background:#04060a;
    border:1px solid var(--border);
    border-radius:10px;
    padding:10px;
    box-shadow:0 20px 60px rgba(0,0,0,.6), 0 0 0 1px rgba(88,166,255,.05) inset;
  }
  #sand{
    display:block;
    image-rendering:pixelated;
    image-rendering:crisp-edges;
    cursor:crosshair;
    border-radius:6px;
    background:#04060a;
  }
  .panel{
    background:linear-gradient(180deg,var(--panel),var(--panel2));
    border:1px solid var(--border);
    border-radius:10px;
    padding:16px;
    width:200px;
    box-shadow:0 10px 30px rgba(0,0,0,.4);
  }
  .panel h2{
    font-size:10px;
    text-transform:uppercase;
    letter-spacing:2px;
    color:var(--muted);
    margin:0 0 12px;
    font-weight:600;
  }
  .mat-btn{
    display:flex;
    align-items:center;
    gap:10px;
    width:100%;
    padding:9px 11px;
    margin-bottom:6px;
    background:#0d1117;
    border:1px solid var(--border);
    border-radius:7px;
    color:var(--text);
    font-size:13px;
    font-family:inherit;
    cursor:pointer;
    transition:transform .08s, border-color .15s, background .15s;
    text-align:left;
  }
  .mat-btn:hover{border-color:#3d4a5e;transform:translateX(2px)}
  .mat-btn:active{transform:translateX(0) scale(.98)}
  .mat-btn.active{
    border-color:var(--accent);
    background:linear-gradient(90deg,#16203a,#0d1117);
    box-shadow:0 0 0 1px var(--accent) inset, 0 0 12px rgba(88,166,255,.15);
  }
  .swatch{
    width:14px;height:14px;border-radius:4px;
    border:1px solid rgba(255,255,255,.18);
    box-shadow:0 0 6px rgba(0,0,0,.4) inset;
    flex-shrink:0;
  }
  .clear-btn{
    width:100%;
    padding:10px;
    margin-top:12px;
    background:linear-gradient(180deg,#2a1a1f,#1a1015);
    border:1px solid #5c2a2a;
    border-radius:7px;
    color:#ffb3b3;
    font-size:12px;
