  }
  .brush-row input{flex:1;accent-color:var(--accent)}
  #brush-val{
    min-width:14px;text-align:right;color:var(--text);font-variant-numeric:tabular-nums;
  }
  .info{
    font-size:11px;color:var(--muted);
    margin-top:14px;line-height:1.6;
    padding-top:12px;border-top:1px solid var(--border);
  }
  .info b{color:var(--text);font-weight:600}
  .legend{display:flex;gap:6px;flex-wrap:wrap;margin-top:8px}
  .legend span{display:inline-flex;align-items:center;gap:4px;font-size:10px;color:var(--muted)}
  .legend i{width:8px;height:8px;border-radius:2px;display:inline-block}
</style>
</head>
<body>
  <h1>Falling Sand</h1>
  <div class="sub">Cellular Automata Sandbox</div>
  <div class="wrap">
    <div class="canvas-wrap">
      <canvas id="sand" width="500" height="500"></canvas>
    </div>
    <div class="panel">
      <h2>Material</h2>
      <button class="mat-btn active" id="mat-sand"><span class="swatch" style="background:#e0c068"></span>Sand</button>
      <button class="mat-btn" id="mat-water"><span class="swatch" style="background:#3a8fd4"></span>Water</button>
      <button class="mat-btn" id="mat-wall"><span class="swatch" style="background:#7a7a82"></span>Wall</button>
      <button class="mat-btn" id="mat-acid"><span class="swatch" style="background:#7fd44a"></span>Acid</button>
      <button class="mat-btn" id="mat-empty"><span class="swatch" style="background:#0a0d12;border-color:#2a3445"></span>Eraser</button>
      <button class="clear-btn" id="clear">Clear All</button>
      <div class="brush-row">
        <span>Brush</span>
        <input type="range" id="brush" min="1" max="6" value="2">
        <span id="brush-val">2</span>
      </div>
      <div class="info">
        <b>Drag</b> to paint. Sand sinks through liquids. Acid erodes walls &amp; sand. Bottom &amp; edges are solid.
      </div>
    </div>
  </div>

<script>
"use strict";
/* ===== Materials ===== */
const EMPTY=0, SAND=1, WATER=2, WALL=3, ACID=4;
const MAT_NAME=["empty","sand","water","wall","acid"];
const MAT_ID={empty:EMPTY, sand:SAND, water:WATER, wall:WALL, acid:ACID};

/* ===== Grid ===== */
const W=100, H=100;          // cells (>=80x80)
const CELL=5;                 // px per cell
const canvas=document.getElementById("sand");
canvas.width=W*CELL;
canvas.height=H*CELL;
const ctx=canvas.getContext("2d");
ctx.imageSmoothingEnabled=false;

const grid=new Uint8Array(W*H);
const moved=new Uint8Array(W*H);
const shade=new Uint8Array(W*H); // subtle per-cell shading for texture

/* offscreen low-res canvas for fast pixel rendering */
const off=document.createElement("canvas");
off.width=W; off.height=H;
const offCtx=off.getContext("2d");
const offImg=offCtx.createImageData(W,H);

function idx(x,y){return y*W+x;}
function inBounds(x,y){return x>=0&&x<W&&y>=0&&y<H;}

/* ===== Public API on window.sim ===== */
window.sim={
  w:W, h:H,
  get(x,y){
    if(!inBounds(x,y)) return "wall"; // OOB acts as solid boundary
    return MAT_NAME[grid[idx(x,y)]];
  },
  set(x,y,material){
    if(!inBounds(x,y)) return;
    const m=MAT_ID[material];
    if(m===undefined) return;
    const i=idx(x,y);
    grid[i]=m;
    if(m===SAND) shade[i]=(Math.random()*40)|0;
    else shade[i]=0;
  },
  clear(){ grid.fill(EMPTY); shade.fill(0); moved.fill(0); },
  tick(n){ for(let k=0;k<n;k++) step(); }
};

/* ===== UI wiring ===== */
let currentMat=SAND;
const matBtns={
  sand:document.getElementById("mat-sand"),
  water:document.getElementById("mat-water"),
  wall:document.getElementById("mat-wall"),
  acid:document.getElementById("mat-acid"),
  empty:document.getElementById("mat-empty"),
};
function selectMat(name){
  currentMat=MAT_ID[name];
  for(const k in matBtns) matBtns[k].classList.toggle("active", k===name);
}
matBtns.sand.onclick=()=>selectMat("sand");
matBtns.water.onclick=()=>selectMat("water");
matBtns.wall.onclick=()=>selectMat("wall");
matBtns.acid.onclick=()=>selectMat("acid");
matBtns.empty.onclick=()=>selectMat("empty");

document.getElementById("clear").onclick=()=>window.sim.clear();

const brushInput=document.getElementById("brush");
const brushVal=document.getElementById("brush-val");
let brushSize=2;
brushInput.oninput=()=>{brushSize=+brushInput.value; brushVal.textContent=brushSize;};

/* ===== Painting ===== */
let painting=false, lastPaint=null;
function canvasToCell(clientX,clientY){
  const r=canvas.getBoundingClientRect();
  const sx=canvas.width/r.width, sy=canvas.height/r.height;
  const px=(clientX-r.left)*sx, py=(clientY-r.top)*sy;
  return {x:Math.floor(px/CELL), y:Math.floor(py/CELL)};
}
function paintAt(x,y){
  const r=brushSize;
  for(let dy=-r;dy<=r;dy++){
    for(let dx=-r;dx<=r;dx++){
      if(dx*dx+dy*dy>r*r+1) continue;
      const nx=x+dx, ny=y+dy;
      if(!inBounds(nx,ny)) continue;
      const i=idx(nx,ny);
      grid[i]=currentMat;
      if(currentMat===SAND) shade[i]=(Math.random()*40)|0;
      else shade[i]=0;
    }
  }
}
function paintLine(x0,y0,x1,y1){
  const dx=x1-x0, dy=y1-y0;
  const steps=Math.max(Math.abs(dx),Math.abs(dy));
  if(steps===0){paintAt(x0,y0);return;}
  for(let i=0;i<=steps;i++){
    const t=i/steps;
    paintAt(Math.round(x0+dx*t),Math.round(y0+dy*t));
  }
}
canvas.addEventListener("mousedown",e=>{
  painting=true;
  const p=canvasToCell(e.clientX,e.clientY);
  paintAt(p.x,p.y); lastPaint=p;
});
window.addEventListener("mousemove",e=>{
  if(!painting) return;
  const p=canvasToCell(e.clientX,e.clientY);
  if(lastPaint) paintLine(lastPaint.x,lastPaint.y,p.x,p.y);
  else paintAt(p.x,p.y);
  lastPaint=p;
});
window.addEventListener("mouseup",()=>{painting=false; lastPaint=null;});
canvas.addEventListener("touchstart",e=>{
  e.preventDefault(); painting=true;
  const t=e.touches[0]; const p=canvasToCell(t.clientX,t.clientY);
  paintAt(p.x,p.y); lastPaint=p;
},{passive:false});
canvas.addEventListener("touchmove",e=>{
  e.preventDefault(); if(!painting) return;
  const t=e.touches[0]; const p=canvasToCell(t.clientX,t.clientY);
  if(lastPaint) paintLine(lastPaint.x,lastPaint.y,p.x,p.y);
  lastPaint=p;
},{passive:false});
canvas.addEventListener("touchend",()=>{painting=false; lastPaint=null;});

/* ===== Simulation ===== */
function rand(n){return (Math.random()*n)|0;}

function step(){
  moved.fill(0);
  // Process bottom-row-up so each particle moves at most one cell per step.
  for(let y=H-1; y>=0; y--){
    for(let x=0; x<W; x++){
      const i=idx(x,y);
      if(moved[i]) continue;
      const m=grid[i];
      if(m===EMPTY||m===WALL) continue;
      if(m===SAND) stepSand(x,y,i);
      else if(m===WATER) stepWater(x,y,i);
      else if(m===ACID) stepAcid(x,y,i);
    }
  }
}

function stepSand(x,y,i){
  if(y+1<H){
    const bi=idx(x,y+1);
    const b=grid[bi];
    if(b===EMPTY){
      grid[bi]=SAND; grid[i]=EMPTY;
      shade[bi]=shade[i]; shade[i]=0;
      moved[bi]=1; moved[i]=1; return;
    }
    if(b===WATER||b===ACID){
      // sand sinks: swap, liquid displaced upward by ONE cell (local only)
      grid[bi]=SAND; grid[i]=b;
      const sh=shade[i]; shade[bi]=sh; shade[i]=0;
      moved[bi]=1; moved[i]=1; return;
    }
    // blocked: try diagonal slide, randomize first direction
    const dir=rand(2)===0?-1:1;
    for(const d of [dir,-dir]){
      const nx=x+d, ny=y+1;
      if(nx<0||nx>=W||ny>=H) continue;
      const ni=idx(nx,ny);
      const n=grid[ni];
      if(n===EMPTY){
        grid[ni]=SAND; grid[i]=EMPTY;
        shade[ni]=shade[i]; shade[i]=0;
        moved[ni]=1; moved[i]=1; return;
      }
      if(n===WATER||n===ACID){
        grid[ni]=SAND; grid[i]=n;
        shade[ni]=shade[i]; shade[i]=0;
        moved[ni]=1; moved[i]=1; return;
      }
    }
  }
  // rest
}

function stepWater(x,y,i){
  if(y+1<H){
    const bi=idx(x,y+1);
    const b=grid[bi];
    if(b===EMPTY){
      grid[bi]=WATER; grid[i]=EMPTY;
      moved[bi]=1; moved[i]=1; return;
    }
    // water does NOT push sand/wall/acid below (no anti-gravity)
  }
  // spread horizontally, randomize direction
  const dir=rand(2)===0?-1:1;
  for(const d of [dir,-dir]){
    const nx=x+d;
    if(nx<0||nx>=W) continue;
    const ni=idx(nx,y);
    if(grid[ni]===EMPTY){
      grid[ni]=WATER; grid[i]=EMPTY;
      moved[ni]=1; moved[i]=1; return;
    }
  }
}

function stepAcid(x,y,i){
  // dissolve sand/wall below or beside (walls must erode)
  const dirs=[[0,1],[-1,0],[1,0]];
  for(let k=dirs.length-1;k>0;k--){
    const j=rand(k+1);
    const t=dirs[k]; dirs[k]=dirs[j]; dirs[j]=t;
  }
  for(const [dx,dy] of dirs){
    const nx=x+dx, ny=y+dy;
    if(nx<0||nx>=W||ny<0||ny>=H) continue;
    const ni=idx(nx,ny);
    const n=grid[ni];
    if((n===SAND||n===WALL) && Math.random()<0.3){
      grid[ni]=EMPTY; shade[ni]=0; moved[ni]=1;
      // acid may be consumed in the reaction
      if(Math.random()<0.25){
        grid[i]=EMPTY; moved[i]=1; return;
      }
      moved[i]=1; return; // one action per tick
    }
  }
  // otherwise move like water (and sink through water)
  if(y+1<H){
    const bi=idx(x,y+1);
    const b=grid[bi];
    if(b===EMPTY){ grid[bi]=ACID; grid[i]=EMPTY; moved[bi]=1; moved[i]=1; return; }
    if(b===WATER){ grid[bi]=ACID; grid[i]=WATER; moved[bi]=1; moved[i]=1; return; }
  }
  const dir=rand(2)===0?-1:1;
  for(const d of [dir,-dir]){
    const nx=x+d;
    if(nx<0||nx>=W) continue;
    const ni=idx(nx,y);
    const n=grid[ni];
    if(n===EMPTY){ grid[ni]=ACID; grid[i]=EMPTY; moved[ni]=1; moved[i]=1; return; }
    if(n===WATER){ grid[ni]=ACID; grid[i]=WATER; moved[ni]=1; moved[i]=1; return; }
  }
}

/* ===== Render ===== */
function render(){
  const d=offImg.data;
  for(let i=0;i<W*H;i++){
    const m=grid[i];
    let r,g,b;
    if(m===EMPTY){ r=6; g=9; b=14; }
    else if(m===SAND){
      const s=shade[i];
      r=224-s; g=192-s; b=104-(s>>1);
    }
    else if(m===WATER){
      // slight vertical tint
      const y=(i/W)|0;
      const v=8-((y%3)*2);
      r=44; g=120+v; b=210;
    }
    else if(m===WALL){
      const s=(shade[i]&15);
      r=110-s; g=110-s; b=120-s;
    }
    else if(m===ACID){
      const s=shade[i];
      r=120; g=210-s; b=70;
    }
    const o=i*4;
    d[o]=r; d[o+1]=g; d[o+2]=b; d[o+3]=255;
  }
  offCtx.putImageData(offImg,0,0);
  ctx.imageSmoothingEnabled=false;
  ctx.drawImage(off,0,0,canvas.width,canvas.height);
}

/* ===== Main loop ===== */
function loop(){
  step();
  render();
  requestAnimationFrame(loop);
}
loop();
</script>
</body>
</html>
